SELECT data_timestamp, MAX(data_value) AS max_data_value
FROM resource_data
WHERE data_timestamp = '2023-10-02 11:00:00';

SELECT COUNT(data_id) AS good_data_count, AVG(CAST(data_value AS REAL)) AS avg_value
FROM resource_data
WHERE data_quality = 'good';

SELECT device_name AS DeviceName
FROM devices
ORDER BY device_name;

SELECT COUNT(*) 
FROM device_commands 
WHERE command_status = 'completed';

SELECT command_status
FROM device_commands
WHERE created_by = 0;

SELECT command_status, COUNT(command_id) AS command_count
FROM device_commands
GROUP BY command_status;

SELECT command, command_status, created_at
FROM device_commands
WHERE created_by = (SELECT user_id FROM users WHERE user_name = 'Bob Williams');

SELECT MAX(data_timestamp) AS latest_timestamp
FROM resource_data
WHERE resource_id = 1;
